import numpy as np

def kl_divergence(p, q):
    p = np.asarray(p, dtype=float)
    q = np.asarray(q, dtype=float)

    if not (np.all(p >= 0) and np.allclose(np.sum(p), 1.0, atol=1e-6)):
        raise ValueError("p is not a valid probability distribution")
    if not (np.all(q >= 0) and np.allclose(np.sum(q), 1.0, atol=1e-6)):
        raise ValueError("q is not a valid probability distribution")

    # Where p > 0 and q = 0: KL = +inf
    if np.any((p > 0) & (q == 0)):
        return np.inf

    # Compute term-by-term; 0 * log(0/q) = 0
    mask = p > 0
    kl = np.sum(p[mask] * np.log(p[mask] / q[mask]))
    return float(kl)

